report_script:
columns=[
{"fieldname":"sales_invoice","label":"Sales Invoice","fieldtype":"Link","options":"Sales Invoice","width":190},
{"fieldname":"posting_date","label":"Posting Date","fieldtype":"Date","width":120},
{"fieldname":"customer","label":"Customer","fieldtype":"Link","options":"Customer","width":250},
{"fieldname":"customer_group","label":"Customer Group","fieldtype":"Link","options":"Customer Group","width":200},
{"fieldname":"territory","label":"Territory","fieldtype":"Link","options":"Territory","width":170},
{"fieldname":"net_total","label":"Net Total","fieldtype":"Currency","width":120},
{"fieldname":"sales_tax","label":"Sales Tax","fieldtype":"Currency","width":120},
{"fieldname":"grand_total","label":"Grand Total","fieldtype":"Currency","width":120}]
conditions=["si.docstatus=1","si.posting_date BETWEEN %(from_date)s AND %(to_date)s"]
params={"from_date":filters.get("from_date"),"to_date":filters.get("to_date")}
if filters.get("customer"): conditions.append("si.customer=%(customer)s"); params["customer"]=filters.get("customer")
if filters.get("customer_group"): conditions.append("c.customer_group=%(customer_group)s"); params["customer_group"]=filters.get("customer_group")
if filters.get("net_total"): conditions.append("ROUND(si.net_total)=ROUND(%(net_total)s)"); params["net_total"]=filters.get("net_total")
if filters.get("sales_tax"): conditions.append("ROUND(si.total_taxes_and_charges)=ROUND(%(sales_tax)s)"); params["sales_tax"]=filters.get("sales_tax")
if filters.get("grand_total"): conditions.append("ROUND(si.grand_total)=ROUND(%(grand_total)s)"); params["grand_total"]=filters.get("grand_total")
data=frappe.db.sql(f'''SELECT si.name sales_invoice,si.posting_date,si.customer,c.customer_group,si.territory,si.net_total,si.total_taxes_and_charges sales_tax,si.grand_total FROM `tabSales Invoice` si LEFT JOIN `tabCustomer` c ON c.name=si.customer WHERE {' AND '.join(conditions)} ORDER BY si.posting_date DESC,si.name DESC''',params,as_dict=True)
report_summary=[{"label":"Net Total","value":sum(d.net_total for d in data),"datatype":"Currency"},{"label":"Sales Tax","value":sum(d.sales_tax for d in data),"datatype":"Currency"},{"label":"Grand Total","value":sum(d.grand_total for d in data),"datatype":"Currency"}]
data=(columns,data,None,None,report_summary,1)

javascript:
frappe.query_reports["Sales Invoice Summary"]={filters:[
{fieldname:"customer_group",label:"Customer Group",fieldtype:"Link",options:"Customer Group"},
{fieldname:"customer",label:"Customer",fieldtype:"Link",options:"Customer"},
{fieldname:"net_total",label:"Find Net Total",fieldtype:"Currency"},
{fieldname:"sales_tax",label:"Find Sales Tax",fieldtype:"Currency"},
{fieldname:"grand_total",label:"Find Grand Total",fieldtype:"Currency"},
{fieldname:"from_date",label:"From Date",fieldtype:"Date",default:frappe.datetime.year_start(),reqd:1},
{fieldname:"to_date",label:"To Date",fieldtype:"Date",default:frappe.datetime.get_today(),reqd:1}
]};
